// ── Helpers ──────────────────────────────────────────────────────────────────

export function getQuotesByCategory(category?: string): Quote[] {
  if (!category) return ALL_QUOTES;
  return ALL_QUOTES.filter(q => q.category === category);
}

export function getQuoteById(id: number): Quote | undefined {
  return ALL_QUOTES.find(q => q.id === id);
}

export function getRandomQuote(category?: string): Quote | undefined {
  const pool = getQuotesByCategory(category);
  if (pool.length === 0) return undefined;
  return pool[Math.floor(Math.random() * pool.length)];
}

export function getQuoteCountsByCategory(): Record<string, number> {
  return ALL_QUOTES.reduce((acc, q) => {
    acc[q.category] = (acc[q.category] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);
}

export function searchQuotes(search: string): Quote[] {
  const lower = search.toLowerCase();
  return ALL_QUOTES.filter(q =>
    q.content.toLowerCase().includes(lower) ||
    (q.contentEn?.toLowerCase().includes(lower)) ||
    q.author.toLowerCase().includes(lower)
  );
}